  1	import * as React from 'react';
  2	import _ from 'lodash';
  3	import classNames from 'classnames';
  4	import { useTranslation } from 'react-i18next';
  5	import { DomainPropType, DomainTuple } from 'victory-core';
  6	import {
  7	  Chart,
  8	  ChartAxis,
  9	  ChartAxisProps,
 10	  ChartBar,
 11	  ChartGroup,
 12	  ChartThemeColor,
 13	  ChartVoronoiContainer,
 14	} from '@patternfly/react-charts/victory';
 15	import { Alert, Card, CardBody, CardTitle } from '@patternfly/react-core';
 16	import {
 17	  formatDate,
 18	  getXaxisValues,
 19	  hourformat,
 20	  monthYear,
 21	  parsePrometheusDuration,
 22	} from '../pipelines-overview/dateTime';
 23	import { ALL_NAMESPACES_KEY } from '../../consts';
 24	import { LoadingInline } from '../Loading';
 25	import {
 26	  usePipelineMetricsForAllNamespacePoll,
 27	  usePipelineMetricsForNamespaceForPipelinePoll,
 28	  usePipelineMetricsForNamespacePoll,
 29	} from './hooks';
 30	import {
 31	  MetricsQueryPrefix,
 32	  PipelineQuery,
 33	  secondsToMinutesK8s,
 34	} from './utils';
 35	import { roundToNearestSecond } from '../pipelines-overview/utils';
 36	
 37	interface PipelinesAverageDurationProps {
 38	  timespan?: number;
 39	  domain?: DomainPropType;
 40	  bordered?: boolean;
 41	  interval?: number;
 42	  parentName?: string;
 43	  namespace?: string;
 44	}
 45	type DomainType = { x?: DomainTuple; y?: DomainTuple };
 46	
 47	const getChartData = (
 48	  tickValues: number[] | Date[],
 49	  data: any,
 50	  type: string,
 51	) => {
 52	  const chartData = tickValues?.map((value, index) => {
 53	    if (index === 0) {
 54	      // Ensure the first value is always 0
 55	      return {
 56	        x: value,
 57	        y: 0,
 58	      };
 59	    }
 60	    const s = data?.find((d) => {
 61	      const group_date = new Date(Number(d.group_value) * 1000);
 62	      if (type == 'hour') {
 63	        return group_date.getHours() === value;
 64	      }
 65	      if (type == 'day' || type == 'week') {
 66	        return group_date.toDateString() === new Date(value).toDateString();
 67	      }
 68	      if (type == 'month') {
 69	        return group_date.getMonth() === value.getMonth();
 70	      }
 71	    });
 72	    return {
 73	      x: value,
 74	      y: s?.avg_duration || 0,
 75	    };
 76	  });
 77	  return chartData;
 78	};
 79	
 80	const PipelinesAverageDurationK8s: React.FC<PipelinesAverageDurationProps> = ({
 81	  timespan,
 82	  domain,
 83	  bordered,
 84	  interval,
 85	  parentName,
 86	  namespace,
 87	}) => {
 88	  const { t } = useTranslation('plugin__pipelines-console-plugin');
 89	  const startTimespan = timespan - parsePrometheusDuration('1d');
 90	  const endDate = new Date(Date.now()).setHours(0, 0, 0, 0);
 91	  const startDate = new Date(Date.now() - startTimespan).setHours(0, 0, 0, 0);
 92	  const { x: domainX, y: domainY } = (domain as DomainType) || {};
 93	  const domainValue: DomainPropType = {
 94	    x: domainX || [startDate, endDate],
 95	    y: domainY || undefined,
 96	  };
 97	  const [tickValues, type] = getXaxisValues(timespan);
 98	  const [averageDurationError, setAverageDurationError] = React.useState<
 99	    string | null
100	  >(null);
101	  const [averageDurationLoading, setAverageDurationLoading] =
102	    React.useState(true);
103	
104	  const [totalPipelineRunsCountData, countError, countLoading] =
105	    parentName && namespace
106	      ? usePipelineMetricsForNamespaceForPipelinePoll({
107	          namespace,
108	          timespan,
109	          delay: interval,
110	          queryPrefix: MetricsQueryPrefix.TEKTON_PIPELINES_CONTROLLER,
111	          name: parentName,
112	          metricsQuery:
113	            PipelineQuery.PIPELINERUN_COUNT_FOR_NAMESPACE_FOR_PIPELINE,
114	          timeout: 90000,
115	        })
116	      : namespace == ALL_NAMESPACES_KEY
117	      ? usePipelineMetricsForAllNamespacePoll({
118	          timespan,
119	          delay: interval,
120	          queryPrefix: MetricsQueryPrefix.TEKTON_PIPELINES_CONTROLLER,
121	          metricsQuery: PipelineQuery.PIPELINERUN_COUNT_FOR_ALL_NAMESPACE,
122	          timeout: 90000,
123	        })
124	      : usePipelineMetricsForNamespacePoll({
125	          namespace,
126	          timespan,
127	          delay: interval,
128	          queryPrefix: MetricsQueryPrefix.TEKTON_PIPELINES_CONTROLLER,
129	          metricsQuery: PipelineQuery.PIPELINERUN_COUNT_FOR_NAMESPACE,
130	          timeout: 90000,
131	        });
132	
133	  const [totalPipelineRunsDurationData, durationError, durationLoading] =
134	    parentName && namespace
135	      ? usePipelineMetricsForNamespaceForPipelinePoll({
136	          namespace,
137	          timespan,
138	          delay: interval,
139	          queryPrefix: MetricsQueryPrefix.TEKTON_PIPELINES_CONTROLLER,
140	          name: parentName,
141	          metricsQuery:
142	            PipelineQuery.PIPELINERUN_DURATION_FOR_NAMESPACE_FOR_PIPELINE,
143	          timeout: 90000,
144	        })
145	      : namespace == ALL_NAMESPACES_KEY
146	      ? usePipelineMetricsForAllNamespacePoll({
147	          timespan,
148	          delay: interval,
149	          queryPrefix: MetricsQueryPrefix.TEKTON_PIPELINES_CONTROLLER,
150	          metricsQuery: PipelineQuery.PIPELINERUN_DURATION_FOR_ALL_NAMESPACE,
151	          timeout: 90000,
152	        })
153	      : usePipelineMetricsForNamespacePoll({
154	          namespace,
155	          timespan,
156	          delay: interval,
157	          queryPrefix: MetricsQueryPrefix.TEKTON_PIPELINES_CONTROLLER,
158	          metricsQuery: PipelineQuery.PIPELINERUN_DURATION_FOR_NAMESPACE,
159	          timeout: 90000,
160	        });
161	
162	  React.useEffect(() => {
163	    const hasNonAbortError =
164	      (countError && countError.name !== 'AbortError') ||
165	      (durationError && durationError.name !== 'AbortError');
166	    setAverageDurationError(
167	      hasNonAbortError ? t('Unable to load average duration') : null,
168	    );
169	  }, [countError, durationError]);
170	
171	  React.useEffect(() => {
172	    setAverageDurationLoading(countLoading || durationLoading);
173	  }, [countLoading, durationLoading]);
174	
175	  const combinedData = totalPipelineRunsCountData?.data?.result[0]?.values?.map(
176	    (value1) => {
177	      const group_value = value1[0];
178	      const runs = parseInt(value1[1]);
179	      const value2 =
180	        totalPipelineRunsDurationData?.data?.result[0]?.values?.find(
181	          (val) =>
182	            roundToNearestSecond(val[0]) === roundToNearestSecond(group_value),
183	        );
184	      const duration = value2 ? parseFloat(value2[1]) : 0;
185	
186	      return { group_value, runs, duration };
187	    },
188	  );
189	
190	  const result = combinedData?.map(({ group_value, runs, duration }, index) => {
191	    if (index === 0) {
192	      return {
193	        group_value,
194	        avg_duration: secondsToMinutesK8s(duration / runs),
195	      };
196	    } else {
197	      const prevDuration = combinedData[index - 1].duration;
198	      const prevRuns = combinedData[index - 1].runs;
199	      if (duration === prevDuration && runs === prevRuns) {
200	        // If both runs and duration are the same as the previous, set avg_duration to 0
201	        return { group_value, avg_duration: 0 };
202	      } else if (duration < prevDuration || runs < prevRuns) {
203	        // Reset condition
204	        return {
205	          group_value,
206	          avg_duration: secondsToMinutesK8s(duration / runs),
207	        };
208	      } else {
209	        // Increment condition
210	        const incrementalDuration = duration - prevDuration;
211	        const incrementalRuns = runs - prevRuns;
212	        const avg_duration = incrementalDuration / incrementalRuns;
213	        return { group_value, avg_duration: secondsToMinutesK8s(avg_duration) };
214	      }
215	    }
216	  });
217	
218	  let xTickFormat;
219	  let dayLabel;
220	  let showLabel = false;
221	  let chartData = [];
222	  switch (type) {
223	    case 'hour':
224	      xTickFormat = (d) => hourformat(d);
225	      showLabel = true;
226	      domainValue.x = [0, 23];
227	      dayLabel = formatDate(new Date());
228	      chartData = getChartData(tickValues, result, 'hour');
229	      break;
230	    case 'day':
231	      xTickFormat = (d) => formatDate(d);
232	      domainValue.x = [startDate, endDate];
233	      chartData = getChartData(tickValues, result, 'day');
234	      break;
235	    case 'week':
236	      xTickFormat = (d) => formatDate(d);
237	      domainValue.x = [new Date(tickValues[0]), new Date(tickValues[11])];
238	      chartData = getChartData(tickValues, result, 'week');
239	      break;
240	    case 'month':
241	      xTickFormat = (d) => monthYear(d);
242	      domainValue.x = [new Date(tickValues[0]), new Date(tickValues[11])];
243	      chartData = getChartData(tickValues, result, 'month');
244	      break;
245	    default:
246	      console.log('Received wrong data');
247	      break;
248	  }
249	  const max = Math.max(...chartData.map((yVal) => yVal.y));
250	  const roundUp = (value, nearest) => {
251	    return Math.ceil(value / nearest) * nearest;
252	  };
253	  const nearest = max > 10 ? 10 : 5;
254	  const roundedMax = roundUp(max, nearest);
255	  domainValue.y =
256	    !isNaN(roundedMax) && roundedMax > 5 ? [0, roundedMax] : [0, 5];
257	
258	  if (!domainY) {
259	    let minY: number = _.minBy(chartData, 'y')?.y ?? 0;
260	    let maxY: number = _.maxBy(chartData, 'y')?.y ?? 0;
261	    if (minY === 0 && maxY === 0) {
262	      minY = -1;
263	      maxY = 1;
264	    } else if (minY > 0 && maxY > 0) {
265	      minY = 0;
266	    } else if (minY < 0 && maxY < 0) {
267	      maxY = 0;
268	    }
269	    domainValue.y = [minY, maxY];
270	  }
271	
272	  let xAxisStyle: ChartAxisProps['style'] = {
273	    tickLabels: { fill: 'var(--pf-t--global--text--color--regular)', fontSize: 12 },
274	  };
275	  const yAxisStyle: ChartAxisProps['style'] = {
276	    tickLabels: { fill: 'var(--pf-t--global--text--color--regular)', fontSize: 12 },
277	  };
278	  if (tickValues.length > 7) {
279	    xAxisStyle = {
280	      tickLabels: {
281	        fill: 'var(--pf-t--global--text--color--regular)',
282	        angle: 320,
283	        fontSize: 10,
284	        textAnchor: 'end',
285	        verticalAnchor: 'end',
286	      },
287	    };
288	  }
289	
290	  return (
291	    <>
292	      <Card
293	        className={classNames('pipeline-overview__number-of-plr-card', {
294	          'card-border': bordered,
295	        })}
296	      >
297	        <CardTitle className="pipeline-overview__number-of-plr-card__title">
298	          <span>{t('Average duration')}</span>
299	        </CardTitle>
300	        <CardBody className="pipeline-overview__number-of-plr-card__body">
301	          {averageDurationError ? (
302	            <Alert
303	              variant="danger"
304	              isInline
305	              title={t('Unable to load average duration')}
306	              className="pf-v6-u-my-lg pf-v6-u-ml-lg"
307	            />
308	          ) : (
309	            <div className="pipeline-overview__number-of-plr-card__bar-chart-div">
310	              {!averageDurationLoading ? (
311	                <Chart
312	                  containerComponent={
313	                    <ChartVoronoiContainer
314	                      labels={({ datum }) => `${datum.y}m`}
315	                      constrainToVisibleArea
316	                    />
317	                  }
318	                  scale={{ x: 'time', y: 'linear' }}
319	                  domain={domainValue}
320	                  domainPadding={{ x: [30, 25] }}
321	                  height={145}
322	                  width={400}
323	                  padding={{
324	                    top: 10,
325	                    bottom: 55,
326	                    left: 50,
327	                  }}
328	                  themeColor={ChartThemeColor.blue}
329	                >
330	                  <ChartAxis
331	                    tickValues={tickValues}
332	                    style={xAxisStyle}
333	                    tickFormat={xTickFormat}
334	                    label={showLabel ? dayLabel : ''}
335	                  />
336	                  <ChartAxis
337	                    dependentAxis
338	                    style={yAxisStyle}
339	                    tickFormat={(v) => `${v}m`}
340	                  />
341	                  <ChartGroup>
342	                    <ChartBar data={chartData} barWidth={18} />
343	                  </ChartGroup>
344	                </Chart>
345	              ) : (
346	                <div className="pipeline-overview__number-of-plr-card__loading pf-v6-u-h-100">
347	                  <LoadingInline />
348	                </div>
349	              )}
350	            </div>
351	          )}
352	        </CardBody>
353	      </Card>
354	    </>
355	  );
356	};
357	
358	export default PipelinesAverageDurationK8s;

