 86	}) => {
 87	  const { t } = useTranslation('plugin__pipelines-console-plugin');
 88	  const startTimespan = timespan - parsePrometheusDuration('1d');
 89	  const endDate = new Date(Date.now()).setHours(0, 0, 0, 0);
 90	  const startDate = new Date(Date.now() - startTimespan).setHours(0, 0, 0, 0);
 91	  const { x: domainX, y: domainY } = (domain as DomainType) || {};
 92	  const domainValue: DomainPropType = {
 93	    x: domainX || [startDate, endDate],
 94	    y: domainY || undefined,
 95	  };
 96	  const [tickValues, type] = getXaxisValues(timespan);
 97	  const [averageDurationError, setAverageDurationError] = React.useState<
 98	    string | null
 99	  >(null);
100	  const [averageDurationLoading, setAverageDurationLoading] =
101	    React.useState(true);
102	
103	  const [totalPipelineRunsCountData, countError, countLoading] =
104	    parentName && namespace
105	      ? usePipelineMetricsForNamespaceForPipelinePoll({
106	          namespace,
107	          timespan,
108	          delay: interval,
109	          queryPrefix: MetricsQueryPrefix.TEKTON_PIPELINES_CONTROLLER,
110	          name: parentName,
111	          metricsQuery:
112	            PipelineQuery.PIPELINERUN_COUNT_FOR_NAMESPACE_FOR_PIPELINE,
113	          timeout: 90000,
114	        })
115	      : namespace == ALL_NAMESPACES_KEY
116	      ? usePipelineMetricsForAllNamespacePoll({
117	          timespan,
118	          delay: interval,
119	          queryPrefix: MetricsQueryPrefix.TEKTON_PIPELINES_CONTROLLER,
120	          metricsQuery: PipelineQuery.PIPELINERUN_COUNT_FOR_ALL_NAMESPACE,
121	          timeout: 90000,
122	        })
123	      : usePipelineMetricsForNamespacePoll({
124	          namespace,
125	          timespan,
126	          delay: interval,
127	          queryPrefix: MetricsQueryPrefix.TEKTON_PIPELINES_CONTROLLER,
128	          metricsQuery: PipelineQuery.PIPELINERUN_COUNT_FOR_NAMESPACE,
129	          timeout: 90000,
130	        });
131	
132	  const [totalPipelineRunsDurationData, durationError, durationLoading] =
133	    parentName && namespace
134	      ? usePipelineMetricsForNamespaceForPipelinePoll({
135	          namespace,
136	          timespan,
137	          delay: interval,
138	          queryPrefix: MetricsQueryPrefix.TEKTON_PIPELINES_CONTROLLER,
139	          name: parentName,
140	          metricsQuery:
141	            PipelineQuery.PIPELINERUN_DURATION_FOR_NAMESPACE_FOR_PIPELINE,
142	          timeout: 90000,
143	        })
144	      : namespace == ALL_NAMESPACES_KEY
145	      ? usePipelineMetricsForAllNamespacePoll({
146	          timespan,
147	          delay: interval,
148	          queryPrefix: MetricsQueryPrefix.TEKTON_PIPELINES_CONTROLLER,
149	          metricsQuery: PipelineQuery.PIPELINERUN_DURATION_FOR_ALL_NAMESPACE,
150	          timeout: 90000,
151	        })
152	      : usePipelineMetricsForNamespacePoll({
153	          namespace,
154	          timespan,
155	          delay: interval,
156	          queryPrefix: MetricsQueryPrefix.TEKTON_PIPELINES_CONTROLLER,
157	          metricsQuery: PipelineQuery.PIPELINERUN_DURATION_FOR_NAMESPACE,
158	          timeout: 90000,
159	        });
160	
161	  React.useEffect(() => {
162	    const hasNonAbortError =
163	      (countError && countError.name !== 'AbortError') ||
164	      (durationError && durationError.name !== 'AbortError');
165	    setAverageDurationError(
166	      hasNonAbortError ? t('Unable to load average duration') : null,
167	    );
168	  }, [countError, durationError]);
169	
170	  React.useEffect(() => {
171	    setAverageDurationLoading(countLoading || durationLoading);
172	  }, [countLoading, durationLoading]);
173	
174	  const combinedData = totalPipelineRunsCountData?.data?.result[0]?.values?.map(
175	    (value1) => {
176	      const group_value = value1[0];
177	      const runs = parseInt(value1[1]);
178	      const value2 =
179	        totalPipelineRunsDurationData?.data?.result[0]?.values?.find(
180	          (val) =>
181	            roundToNearestSecond(val[0]) === roundToNearestSecond(group_value),
182	        );
183	      const duration = value2 ? parseFloat(value2[1]) : 0;
184	
185	      return { group_value, runs, duration };
186	    },
187	  );
188	
189	  const result = combinedData?.map(({ group_value, runs, duration }, index) => {
190	    if (index === 0) {
191	      return {
192	        group_value,
193	        avg_duration: secondsToMinutesK8s(duration / runs),
194	      };
195	    } else {
196	      const prevDuration = combinedData[index - 1].duration;
197	      const prevRuns = combinedData[index - 1].runs;
198	      if (duration === prevDuration && runs === prevRuns) {
199	        // If both runs and duration are the same as the previous, set avg_duration to 0
200	        return { group_value, avg_duration: 0 };
201	      } else if (duration < prevDuration || runs < prevRuns) {
202	        // Reset condition
203	        return {
204	          group_value,
205	          avg_duration: secondsToMinutesK8s(duration / runs),
206	        };
207	      } else {
208	        // Increment condition
209	        const incrementalDuration = duration - prevDuration;
210	        const incrementalRuns = runs - prevRuns;
211	        const avg_duration = incrementalDuration / incrementalRuns;
212	        return { group_value, avg_duration: secondsToMinutesK8s(avg_duration) };
213	      }
214	    }
215	  });
216	
217	  let xTickFormat;
218	  let dayLabel;
219	  let showLabel = false;
220	  let chartData = [];
221	  switch (type) {
222	    case 'hour':
223	      xTickFormat = (d) => hourformat(d);
224	      showLabel = true;
225	      domainValue.x = [0, 23];
226	      dayLabel = formatDate(new Date());
227	      chartData = getChartData(tickValues, result, 'hour');
228	      break;
229	    case 'day':
230	      xTickFormat = (d) => formatDate(d);
231	      domainValue.x = [startDate, endDate];
232	      chartData = getChartData(tickValues, result, 'day');
233	      break;
234	    case 'week':
235	      xTickFormat = (d) => formatDate(d);
236	      domainValue.x = [new Date(tickValues[0]), new Date(tickValues[11])];
237	      chartData = getChartData(tickValues, result, 'week');
238	      break;
239	    case 'month':
240	      xTickFormat = (d) => monthYear(d);
241	      domainValue.x = [new Date(tickValues[0]), new Date(tickValues[11])];
242	      chartData = getChartData(tickValues, result, 'month');
243	      break;
244	    default:
245	      console.log('Received wrong data');
246	      break;
247	  }
248	  const max = Math.max(...chartData.map((yVal) => yVal.y));
249	  const roundUp = (value, nearest) => {
250	    return Math.ceil(value / nearest) * nearest;
251	  };
252	  const nearest = max > 10 ? 10 : 5;
253	  const roundedMax = roundUp(max, nearest);
254	  domainValue.y =
255	    !isNaN(roundedMax) && roundedMax > 5 ? [0, roundedMax] : [0, 5];
256	
257	  if (!domainY) {
258	    let minY: number = _.minBy(chartData, 'y')?.y ?? 0;
259	    let maxY: number = _.maxBy(chartData, 'y')?.y ?? 0;
260	    if (minY === 0 && maxY === 0) {
261	      minY = -1;
262	      maxY = 1;
263	    } else if (minY > 0 && maxY > 0) {
264	      minY = 0;
265	    } else if (minY < 0 && maxY < 0) {
266	      maxY = 0;
267	    }
268	    domainValue.y = [minY, maxY];
269	  }
270	
271	  let xAxisStyle: React.ComponentProps<typeof ChartAxis>['style'] = {
272	    tickLabels: { fill: 'var(--pf-t--global--text--color--regular)', fontSize: 12 },
273	  };
274	  const yAxisStyle: React.ComponentProps<typeof ChartAxis>['style'] = {
275	    tickLabels: { fill: 'var(--pf-t--global--text--color--regular)', fontSize: 12 },
276	  };
277	  if (tickValues.length > 7) {
278	    xAxisStyle = {
279	      tickLabels: {
280	        fill: 'var(--pf-t--global--text--color--regular)',
281	        angle: 320,
282	        fontSize: 10,
283	        textAnchor: 'end',
284	        verticalAnchor: 'end',
285	      },
286	    };
287	  }
288	
289	  return (
290	    <>
291	      <Card
292	        className={classNames('pipeline-overview__number-of-plr-card', {
293	          'card-border': bordered,
294	        })}
295	      >
296	        <CardTitle className="pipeline-overview__number-of-plr-card__title">
297	          <span>{t('Average duration')}</span>
298	        </CardTitle>
299	        <CardBody className="pipeline-overview__number-of-plr-card__body">
300	          {averageDurationError ? (
301	            <Alert
302	              variant="danger"
303	              isInline
304	              title={t('Unable to load average duration')}
305	              className="pf-v6-u-my-lg pf-v6-u-ml-lg"
306	            />
307	          ) : (
308	            <div className="pipeline-overview__number-of-plr-card__bar-chart-div">
309	              {!averageDurationLoading ? (
310	                <Chart
311	                  containerComponent={
312	                    <ChartVoronoiContainer
313	                      labels={({ datum }) => `${datum.y}m`}
314	                      constrainToVisibleArea
315	                    />
316	                  }
317	                  scale={{ x: 'time', y: 'linear' }}
318	                  domain={domainValue}
319	                  domainPadding={{ x: [30, 25] }}
320	                  height={145}
321	                  width={400}
322	                  padding={{
323	                    top: 10,
324	                    bottom: 55,
325	                    left: 50,
326	                  }}
327	                  themeColor={ChartThemeColor.blue}
328	                >
329	                  <ChartAxis
330	                    tickValues={tickValues}
331	                    style={xAxisStyle}
332	                    tickFormat={xTickFormat}
333	                    label={showLabel ? dayLabel : ''}
334	                  />
335	                  <ChartAxis
336	                    dependentAxis
337	                    style={yAxisStyle}
338	                    tickFormat={(v) => `${v}m`}
339	                  />
340	                  <ChartGroup>
341	                    <ChartBar data={chartData} barWidth={18} />
342	                  </ChartGroup>
343	                </Chart>
344	              ) : (
345	                <div className="pipeline-overview__number-of-plr-card__loading pf-v6-u-h-100">
346	                  <LoadingInline />
347	                </div>
348	              )}
349	            </div>
350	          )}
351	        </CardBody>
352	      </Card>
353	    </>
354	  );
355	};
356	
357	export default PipelinesAverageDurationK8s;
